'use client';

import * as React from 'react';
import { type ToastActionElement, type ToastProps } from '@/components/ui/toast';

/**
 * @fileOverview Implementação centralizada e única do hook de Toast para o BarDoLuis.
 * CTO: Este é o local oficial de estado de notificações.
 * CEO: Unificado para garantir que o feedback ao usuário seja instantâneo e sem erros.
 */

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 5000;

type ToasterToast = ToastProps & {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: 'ADD_TOAST',
  UPDATE_TOAST: 'UPDATE_TOAST',
  DISMISS_TOAST: 'DISMISS_TOAST',
  REMOVE_TOAST: 'REMOVE_TOAST',
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type Action = 
  | { type: typeof actionTypes.ADD_TOAST; toast: ToasterToast }
  | { type: typeof actionTypes.UPDATE_TOAST; toast: Partial<ToasterToast> }
  | { type: typeof actionTypes.DISMISS_TOAST; toastId?: ToasterToast['id'] }
  | { type: typeof actionTypes.REMOVE_TOAST; toastId?: ToasterToast['id'] };

interface State {
  toasts: ToasterToast[];
}

const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case actionTypes.ADD_TOAST:
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case actionTypes.UPDATE_TOAST:
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      };

    case actionTypes.DISMISS_TOAST:
      const { toastId } = action;
      if (toastId) {
        return {
          ...state,
          toasts: state.toasts.map((t) =>
            t.id === toastId ? { ...t, open: false } : t
          ),
        };
      } else {
        return {
          ...state,
          toasts: state.toasts.map((t) => ({ ...t, open: false })),
        };
      }

    case actionTypes.REMOVE_TOAST:
      if (action.toastId) {
        return {
          ...state,
          toasts: state.toasts.filter((t) => t.id !== action.toastId),
        };
      }
      return state;
    default:
      return state;
  }
};

const listeners: ((state: State) => void)[] = [];
let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) => listener(memoryState));
}

export function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  const toast = React.useCallback(({ ...props }: Omit<ToasterToast, 'id'>) => {
    const id = genId();

    const update = (props: Partial<ToasterToast>) =>
      dispatch({ type: actionTypes.UPDATE_TOAST, toast: { ...props, id } });
    const dismiss = () =>
      dispatch({ type: actionTypes.DISMISS_TOAST, toastId: id });
    const remove = () =>
      dispatch({ type: actionTypes.REMOVE_TOAST, toastId: id });

    dispatch({ 
      type: actionTypes.ADD_TOAST, 
      toast: { ...props, id, open: true, onOpenChange: (open) => { if (!open) dismiss(); } } 
    });

    return { id, update, dismiss, remove };
  }, []);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: actionTypes.DISMISS_TOAST, toastId }),
  };
}

export const toast = (props: Omit<ToasterToast, 'id'>) => {
  const id = genId();
  dispatch({ 
    type: actionTypes.ADD_TOAST, 
    toast: { ...props, id, open: true } 
  });
  return {
    id,
    dismiss: () => dispatch({ type: actionTypes.DISMISS_TOAST, toastId: id }),
    update: (updatedProps: Partial<ToasterToast>) => dispatch({ type: actionTypes.UPDATE_TOAST, toast: { ...updatedProps, id } }),
  };
};
